import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { Clock, Image, Video, ChevronRight, BookOpen } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import ComicPanel from '../components/ComicPanel';
import { ThoughtBubble } from '../components/SpeechBubble';
import SoundEffectBadge from '../components/SoundEffectBadge';

const API_URL = process.env.REACT_APP_BACKEND_URL || '';

function History({ onSelectScan }) {
  const [scans, setScans] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const { t } = useTranslation();

  useEffect(() => {
    fetchHistory();
  }, []);

  const fetchHistory = async () => {
    try {
      const response = await fetch(`${API_URL}/api/history`);
      const data = await response.json();

      if (data.success) {
        setScans(data.scans);
      } else {
        setError('Failed to load history');
      }
    } catch (err) {
      console.error('Fetch history error:', err);
      setError('An error occurred while loading history');
    } finally {
      setLoading(false);
    }
  };

  const formatDate = (timestamp) => {
    const date = new Date(timestamp);
    return date.toLocaleString();
  };

  if (loading) {
    return (
      <div className="page" data-testid="loading-history">
        <div className="container text-center pt-20">
          <div className="spinner mx-auto" />
          <p className="mt-8 text-lg font-semibold">{t('history.loading')}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="page" data-testid="history-page">
      <div className="container">
        <motion.div
          initial={{ y: -20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
        >
          <ComicPanel className="text-center mb-8">
            <h1 className="text-4xl sm:text-5xl mb-4" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-blue)', textShadow: '3px 3px 0px var(--primary-yellow), 6px 6px 0px var(--border-ink)' }}>
              <BookOpen size={40} className="inline-block mr-3" style={{ verticalAlign: 'middle' }} />
              {t('history.title')}
            </h1>
            <p className="text-base sm:text-lg font-semibold">{t('history.description')}</p>
          </ComicPanel>
        </motion.div>

        {error && (
          <ComicPanel className="max-w-2xl mx-auto mb-8" data-testid="error-message">
            <div className="flex items-start gap-3">
              <span className="text-3xl">❌</span>
              <div>
                <strong className="block text-xl mb-2" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--danger)' }}>
                  {t('history.error')}
                </strong>
                <p className="font-semibold">{error}</p>
              </div>
            </div>
          </ComicPanel>
        )}

        {scans.length === 0 ? (
          <motion.div
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            className="max-w-2xl mx-auto"
            data-testid="empty-history"
          >
            <ComicPanel className="text-center py-12">
              <ThoughtBubble className="inline-block">
                <Clock size={64} className="mx-auto mb-4" style={{ color: 'var(--primary-blue)' }} />
                <h3 className="text-4xl mb-4" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-blue)' }}>
                  {t('history.noScans')}
                </h3>
                <p className="text-lg font-semibold mb-4">
                  {t('history.noScansDesc')}
                </p>
                <SoundEffectBadge variant="red" rotation={-8}>{t('home.pow')}</SoundEffectBadge>
              </ThoughtBubble>
            </ComicPanel>
          </motion.div>
        ) : (
          <div className="grid grid-cols-1 gap-6">
            {scans.map((scan, index) => (
              <motion.div
                key={scan.id || scan._id || index}
                initial={{ x: -20, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                transition={{ delay: index * 0.1 }}
                whileHover={{ scale: 1.02, x: 8 }}
                onClick={() => onSelectScan(scan)}
                data-testid={`scan-item-${index}`}
              >
                <ComicPanel 
                  className="cursor-pointer flex justify-between items-center relative"
                  style={{
                    background: index % 3 === 0 ? '#E3F2FD' : index % 3 === 1 ? '#FFF9C4' : '#FFE0E0'
                  }}
                >
                  <div className="flex gap-6 items-center flex-1">
                    {/* Icon */}
                    <div 
                      className="p-4 rounded-full flex-shrink-0"
                      style={{
                        background: scan.scan_type === 'image' ? 'var(--primary-blue)' : 'var(--primary-red)',
                        border: '3px solid var(--border-ink)',
                      }}
                    >
                      {scan.scan_type === 'image' ? (
                        <Image size={32} style={{ color: 'white' }} />
                      ) : (
                        <Video size={32} style={{ color: 'white' }} />
                      )}
                    </div>

                    {/* Content */}
                    <div>
                      <div className="text-2xl mb-2" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--ink)' }}>
                        {scan.theory?.theory_title || 'Analysis Complete'}
                      </div>
                      <div className="text-base font-semibold opacity-70" style={{ color: 'var(--ink-2)' }}>
                        📅 {formatDate(scan.timestamp)}
                        {scan.comic_matches && scan.comic_matches.length > 0 && (
                          <span className="ml-4">
                            📖 {scan.comic_matches.length} {scan.comic_matches.length === 1 ? t('history.comicMatch') : t('history.comicMatches')}
                          </span>
                        )}
                      </div>
                    </div>
                  </div>

                  {/* Arrow */}
                  <ChevronRight size={32} style={{ color: 'var(--primary-blue)' }} className="flex-shrink-0" />
                </ComicPanel>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default History;
