import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X } from 'lucide-react';

const CHARACTER_QUOTES = {
  success: [
    { character: '🕷️ Spider-Man', quote: 'With great scans come great theories!', color: '#FF0000' },
    { character: '🦇 Batman', quote: "I'm vengeance... I'm the night... I'm analyzing your footage!", color: '#1A1A1A' },
    { character: '⚡ Flash', quote: 'That was faster than me finding easter eggs!', color: '#FFD700' },
    { character: '🛡️ Captain America', quote: 'I can do this all day... analyzing comics!', color: '#0066FF' },
    { character: '🤖 Iron Man', quote: 'JARVIS, we found something interesting!', color: '#FF6600' },
    { character: '💚 Hulk', quote: 'HULK SMASH... wait, Hulk found cool reference!', color: '#00CC00' },
    { character: '⭐ Wonder Woman', quote: 'By the gods! Look at these connections!', color: '#9900FF' }
  ],
  scanning: [
    { character: '🕷️ Spider-Man', quote: 'My spider-sense is tingling... analyzing!', color: '#FF0000' },
    { character: '🦇 Batman', quote: 'Running it through the Batcomputer...', color: '#1A1A1A' },
    { character: '⚡ Flash', quote: 'Give me a microsecond...', color: '#FFD700' }
  ]
};

function CharacterThoughtBubble({ show, onClose, type = 'success' }) {
  if (!show) return null;

  const quotes = CHARACTER_QUOTES[type] || CHARACTER_QUOTES.success;
  const randomQuote = quotes[Math.floor(Math.random() * quotes.length)];

  return (
    <AnimatePresence>
      {show && (
        <motion.div
          initial={{ scale: 0, opacity: 0, y: 50 }}
          animate={{ scale: 1, opacity: 1, y: 0 }}
          exit={{ scale: 0, opacity: 0, y: 50 }}
          transition={{ type: 'spring', duration: 0.5 }}
          style={{
            position: 'fixed',
            bottom: '2rem',
            right: '2rem',
            zIndex: 1000,
            maxWidth: '350px'
          }}
          data-testid="character-thought-bubble"
        >
          <div
            className="thought-bubble-animated"
            style={{
              background: 'white',
              border: `4px solid ${randomQuote.color}`,
              borderRadius: '20px',
              padding: '1.5rem',
              boxShadow: '6px 6px 0px rgba(0, 0, 0, 0.3)',
              position: 'relative'
            }}
          >
            <button
              onClick={onClose}
              style={{
                position: 'absolute',
                top: '0.5rem',
                right: '0.5rem',
                background: 'transparent',
                border: 'none',
                cursor: 'pointer',
                padding: '0.25rem'
              }}
              data-testid="close-thought-bubble"
            >
              <X size={20} />
            </button>
            
            <div style={{ marginBottom: '0.75rem' }}>
              <span style={{ fontSize: '2rem' }}>{randomQuote.character.split(' ')[0]}</span>
              <span
                style={{
                  marginLeft: '0.5rem',
                  fontFamily: '"Bangers", cursive',
                  fontSize: '1.1rem',
                  color: randomQuote.color,
                  textShadow: '2px 2px 0px rgba(0, 0, 0, 0.1)'
                }}
              >
                {randomQuote.character.split(' ').slice(1).join(' ')}
              </span>
            </div>
            
            <p
              style={{
                fontFamily: '"Comic Neue", cursive',
                fontSize: '1.1rem',
                fontWeight: 700,
                color: '#1A1A1A',
                lineHeight: 1.4,
                margin: 0
              }}
            >
              &quot;{randomQuote.quote}&quot;
            </p>
            
            {/* Speech bubble tail */}
            <div
              style={{
                position: 'absolute',
                bottom: '-20px',
                right: '30px',
                width: 0,
                height: 0,
                borderLeft: '15px solid transparent',
                borderRight: '15px solid transparent',
                borderTop: `20px solid ${randomQuote.color}`
              }}
            />
            <div
              style={{
                position: 'absolute',
                bottom: '-15px',
                right: '33px',
                width: 0,
                height: 0,
                borderLeft: '12px solid transparent',
                borderRight: '12px solid transparent',
                borderTop: '17px solid white',
                zIndex: 1
              }}
            />
            
            {/* Small thought circles */}
            <div
              style={{
                position: 'absolute',
                bottom: '-35px',
                right: '60px',
                width: '15px',
                height: '15px',
                background: 'white',
                border: `3px solid ${randomQuote.color}`,
                borderRadius: '50%'
              }}
            />
            <div
              style={{
                position: 'absolute',
                bottom: '-50px',
                right: '80px',
                width: '10px',
                height: '10px',
                background: 'white',
                border: `3px solid ${randomQuote.color}`,
                borderRadius: '50%'
              }}
            />
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

export default CharacterThoughtBubble;
