import React from 'react';

/**
 * SoundEffectBadge - Comic book sound effect labels
 * Used for action buttons and emphasis (POW!, ZAP!, BOOM!, etc.)
 */
export const SoundEffectBadge = ({ 
  children, 
  variant = 'red', 
  className = '', 
  rotation = -5,
  ...props 
}) => {
  const variants = {
    red: { bg: 'var(--primary-red)', color: '#ffffff' },
    yellow: { bg: 'var(--primary-yellow)', color: 'var(--ink)' },
    blue: { bg: 'var(--primary-blue)', color: '#ffffff' },
    green: { bg: 'var(--success)', color: '#ffffff' },
  };

  const colors = variants[variant] || variants.red;

  return (
    <span
      className={`inline-block px-3 py-1 uppercase text-base tracking-wide rounded-lg ${className}`}
      style={{
        background: colors.bg,
        color: colors.color,
        border: '3px solid var(--border-ink)',
        boxShadow: '3px 3px 0 var(--border-ink)',
        fontFamily: 'Bangers, system-ui',
        transform: `rotate(${rotation}deg)`,
      }}
      {...props}
    >
      {children}
    </span>
  );
};

export default SoundEffectBadge;
