/**
 * Gemini 1.5 Flash AI Service - Frontend
 * Connects to backend Gemini endpoints
 */

const API_URL = process.env.REACT_APP_BACKEND_URL || '';

class GeminiAIService {
  constructor() {
    this.language = 'uk'; // Default Ukrainian
  }

  setLanguage(lang) {
    this.language = lang || 'uk';
  }

  async analyzeImage(imageBase64) {
    try {
      console.log('🎯 Sending to Gemini for analysis...');
      
      const response = await fetch(`${API_URL}/api/gemini/analyze-image`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          image_base64: imageBase64,
          language: this.language
        }),
      });

      if (!response.ok) {
        throw new Error(`Gemini API error: ${response.status}`);
      }

      const result = await response.json();
      
      if (!result.success) {
        throw new Error('Gemini analysis failed');
      }

      console.log('✅ Gemini vision analysis complete');
      return result.data;
    } catch (error) {
      console.error('❌ Gemini analysis error:', error);
      throw error;
    }
  }

  async generateTheory(visionData, matches = []) {
    try {
      console.log('🎯 Generating theory with Gemini...');
      
      const response = await fetch(`${API_URL}/api/gemini/generate-theory`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          vision_data: visionData,
          language: this.language
        }),
      });

      if (!response.ok) {
        throw new Error(`Gemini API error: ${response.status}`);
      }

      const result = await response.json();
      
      if (!result.success) {
        throw new Error('Theory generation failed');
      }

      console.log('✅ Theory generated');
      return result.data;
    } catch (error) {
      console.error('❌ Theory generation error:', error);
      throw error;
    }
  }

  async deepVideoAnalysis(videoUrl, frameCount = 10, onProgress = null) {
    try {
      console.log(`🎬 Starting deep sequence scan (${frameCount} frames)...`);
      
      if (onProgress) onProgress(0.1, `🎞️ Extracting ${frameCount} video frames...`);
      
      const response = await fetch(`${API_URL}/api/gemini/deep-video-analysis`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          video_url: videoUrl,
          language: this.language,
          frame_count: frameCount
        }),
      });

      if (!response.ok) {
        throw new Error(`Deep video analysis error: ${response.status}`);
      }

      if (onProgress) onProgress(0.5, 'Analyzing deep frame sequence...');

      const result = await response.json();
      
      if (!result.success) {
        throw new Error('Deep video analysis failed');
      }

      if (onProgress) onProgress(1.0, '✅ Deep sequence scan complete!');

      console.log(`✅ Deep video analysis complete (${result.data.frames_analyzed} frames)`);
      return result.data;
    } catch (error) {
      console.error('❌ Deep video analysis error:', error);
      throw error;
    }
  }
}

export default GeminiAIService;
