import React, { useState } from 'react';
import './App.css';
import './i18n'; // Initialize i18next
import Home from './pages/Home';
import History from './pages/History';
import ResultDetail from './pages/ResultDetail';
import Settings from './pages/Settings';
import { Camera, History as HistoryIcon, Sparkles, Settings as SettingsIcon } from 'lucide-react';
import { useTranslation } from 'react-i18next';

function App() {
  const [currentPage, setCurrentPage] = useState('home');
  const [selectedScan, setSelectedScan] = useState(null);
  const { t } = useTranslation();

  const renderPage = () => {
    switch (currentPage) {
      case 'home':
        return <Home onScanComplete={(scan) => {
          setSelectedScan(scan);
          setCurrentPage('result');
        }} />;
      case 'history':
        return <History onSelectScan={(scan) => {
          setSelectedScan(scan);
          setCurrentPage('result');
        }} />;
      case 'result':
        return <ResultDetail scan={selectedScan} onBack={() => setCurrentPage('home')} />;
      case 'settings':
        return <Settings />;
      default:
        return <Home onScanComplete={(scan) => {
          setSelectedScan(scan);
          setCurrentPage('result');
        }} />;
    }
  };

  return (
    <div className="App v2-layout" data-testid="app-container" translate="no">
      {/* Navigation */}
      <nav className="nav" data-testid="navigation">
        <div className="nav-content">
          <div 
            className="logo" 
            onClick={() => setCurrentPage('home')}
            data-testid="logo"
          >
            <Sparkles size={24} style={{ display: 'inline', verticalAlign: 'middle' }} />
            LOREHUNTER AI
          </div>
          <div className="nav-links">
            <span
              className={`nav-link ${currentPage === 'home' ? 'active' : ''}`}
              onClick={() => setCurrentPage('home')}
              data-testid="nav-scan"
            >
              <Camera size={20} />
              {t('nav.scan')}
            </span>
            <span
              className={`nav-link ${currentPage === 'history' ? 'active' : ''}`}
              onClick={() => setCurrentPage('history')}
              data-testid="nav-history"
            >
              <HistoryIcon size={20} />
              {t('nav.history')}
            </span>
            <span
              className={`nav-link ${currentPage === 'settings' ? 'active' : ''}`}
              onClick={() => setCurrentPage('settings')}
              data-testid="nav-settings"
            >
              <SettingsIcon size={20} />
              {t('nav.settings')}
            </span>
          </div>
        </div>
      </nav>

      {/* Page Content */}
      <main>{renderPage()}</main>
    </div>
  );
}

export default App;
