import React, { useState, useEffect } from 'react';
import { Film, Loader2 } from 'lucide-react';

/**
 * PosterWithFallback Component
 * 
 * Implements 4-tier fallback system for poster images:
 * Tier 1: Try AI-provided URL
 * Tier 2: Try backend proxy (CORS-safe)
 * Tier 3: Try Emergent LLM search for reliable URL
 * Tier 4: Render stylized CSS fallback card
 * 
 * CRITICAL: Never renders '?' or broken image icons
 */
function PosterWithFallback({ posterUrl, title, year, className, style }) {
  const [currentTier, setCurrentTier] = useState(1);
  const [imageUrl, setImageUrl] = useState(posterUrl);
  const [isLoading, setIsLoading] = useState(!!posterUrl);
  const [showFallback, setShowFallback] = useState(!posterUrl);

  const BACKEND_URL = process.env.REACT_APP_BACKEND_URL || '';

  useEffect(() => {
    // Reset state when posterUrl changes
    if (posterUrl) {
      setCurrentTier(1);
      setImageUrl(posterUrl);
      setIsLoading(true);
      setShowFallback(false);
    } else {
      // No URL provided at all - go straight to fallback
      setShowFallback(true);
      setIsLoading(false);
    }
  }, [posterUrl]);

  const handleImageError = async () => {
    console.warn(`Tier ${currentTier} failed for poster:`, imageUrl);

    if (currentTier === 1 && posterUrl) {
      // Tier 2: Try via backend proxy
      console.log('Attempting Tier 2: Backend proxy');
      setCurrentTier(2);
      setImageUrl(`${BACKEND_URL}/api/proxy-image?url=${encodeURIComponent(posterUrl)}`);
    } else if (currentTier === 2 && title) {
      // Tier 3: Try Emergent LLM search
      console.log('Attempting Tier 3: LLM-assisted poster search');
      setCurrentTier(3);
      setIsLoading(true);
      
      try {
        const response = await fetch(`${BACKEND_URL}/api/search-poster`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ title, year })
        });
        
        const data = await response.json();
        
        if (data.success && data.poster_url) {
          console.log('Tier 3 success:', data.poster_url, 'from', data.source);
          setImageUrl(data.poster_url);
          setIsLoading(false);
        } else {
          // Tier 3 failed - go to Tier 4
          console.log('Tier 3 failed, using Tier 4: Stylized fallback');
          setCurrentTier(4);
          setShowFallback(true);
          setIsLoading(false);
        }
      } catch (error) {
        console.error('Tier 3 search error:', error);
        // Go to Tier 4 on error
        setCurrentTier(4);
        setShowFallback(true);
        setIsLoading(false);
      }
    } else {
      // All tiers exhausted - show Tier 4 fallback
      console.log('All tiers exhausted, using Tier 4: Stylized fallback');
      setCurrentTier(4);
      setShowFallback(true);
      setIsLoading(false);
    }
  };

  const handleImageLoad = () => {
    console.log(`Tier ${currentTier} success:`, imageUrl);
    setIsLoading(false);
    setShowFallback(false);
  };

  // Tier 4: Stylized fallback card
  if (showFallback) {
    return (
      <StylizedPosterFallback 
        title={title} 
        className={className}
        style={style}
      />
    );
  }

  return (
    <div className="relative" style={style}>
      {isLoading && (
        <div 
          className="absolute inset-0 flex items-center justify-center bg-gray-100 rounded-lg"
          style={{
            border: '4px solid var(--border-ink, #000)',
            boxShadow: '6px 6px 0px rgba(0,0,0,0.3)',
            ...style
          }}
        >
          <Loader2 
            className="animate-spin" 
            size={48} 
            style={{ color: 'var(--primary-blue, #3b82f6)' }}
          />
        </div>
      )}
      
      <img
        src={imageUrl}
        alt={title || 'Poster'}
        className={className}
        style={{ 
          objectFit: 'contain',
          display: isLoading ? 'none' : 'block',
          ...style
        }}
        onLoad={handleImageLoad}
        onError={handleImageError}
        data-testid="poster-image"
      />
    </div>
  );
}

/**
 * StylizedPosterFallback Component
 * 
 * Premium Marvel-style fallback card when all poster URLs fail
 * Dark gradient (#1a1a1a → #333333) with bold typography
 */
function StylizedPosterFallback({ title, className, style }) {
  return (
    <div 
      className={`stylized-poster-fallback ${className || ''}`}
      style={{
        width: '100%',
        maxWidth: '300px',
        height: '450px',
        background: 'linear-gradient(135deg, #1a1a1a 0%, #333333 100%)',
        border: '4px solid var(--border-ink, #000)',
        borderRadius: '12px',
        boxShadow: '6px 6px 0px rgba(0,0,0,0.3)',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '2rem',
        position: 'relative',
        overflow: 'hidden',
        ...style
      }}
      data-testid="poster-fallback"
    >
      {/* Comic book texture overlay */}
      <div 
        style={{
          position: 'absolute',
          inset: 0,
          background: 'repeating-linear-gradient(45deg, transparent, transparent 10px, rgba(255,255,255,0.03) 10px, rgba(255,255,255,0.03) 20px)',
          pointerEvents: 'none'
        }}
      />
      
      {/* Film icon */}
      <Film 
        size={80} 
        className="mb-6"
        style={{ 
          color: 'var(--primary-yellow, #FFD700)',
          filter: 'drop-shadow(2px 2px 4px rgba(0,0,0,0.5))',
          zIndex: 1
        }}
      />
      
      {/* Title text */}
      <h3 
        style={{
          fontFamily: 'Bangers, system-ui, sans-serif',
          fontSize: 'clamp(1.25rem, 4vw, 2rem)',
          color: '#ffffff',
          textAlign: 'center',
          textTransform: 'uppercase',
          letterSpacing: '0.05em',
          lineHeight: 1.2,
          textShadow: '3px 3px 6px rgba(0,0,0,0.8)',
          zIndex: 1,
          wordWrap: 'break-word',
          maxWidth: '100%'
        }}
      >
        {title || 'No Poster Available'}
      </h3>
      
      {/* "Comic Archive" badge */}
      <div 
        style={{
          position: 'absolute',
          bottom: '1rem',
          left: '50%',
          transform: 'translateX(-50%)',
          background: 'var(--primary-red, #DC3545)',
          color: 'white',
          padding: '0.5rem 1rem',
          borderRadius: '8px',
          border: '2px solid var(--border-ink, #000)',
          fontWeight: 'bold',
          fontSize: '0.75rem',
          textTransform: 'uppercase',
          letterSpacing: '0.1em',
          boxShadow: '2px 2px 4px rgba(0,0,0,0.4)',
          zIndex: 1
        }}
      >
        Comic Archive
      </div>
    </div>
  );
}

export default PosterWithFallback;
export { StylizedPosterFallback };
