import React from 'react';
import { motion } from 'framer-motion';
import { Settings as SettingsIcon, Globe, Zap } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import ComicPanel from '../components/ComicPanel';
import { SpeechBubble } from '../components/SpeechBubble';
import SoundEffectBadge from '../components/SoundEffectBadge';

function Settings() {
  const { t, i18n } = useTranslation();

  const languages = [
    { code: 'en', name: t('languages.en') },
    { code: 'de', name: t('languages.de') },
    { code: 'fr', name: t('languages.fr') },
    { code: 'uk', name: t('languages.uk') },
    { code: 'zh', name: t('languages.zh') },
    { code: 'ko', name: t('languages.ko') },
    { code: 'ja', name: t('languages.ja') },
    { code: 'tr', name: t('languages.tr') },
    { code: 'pl', name: t('languages.pl') },
    { code: 'pt', name: t('languages.pt') },
    { code: 'es', name: t('languages.es') },
    { code: 'it', name: t('languages.it') },
  ];

  const handleLanguageChange = (event) => {
    const newLang = event.target.value;
    i18n.changeLanguage(newLang);
  };

  return (
    <div className="page" data-testid="settings-page">
      <div className="container">
        {/* Header */}
        <motion.div
          initial={{ y: -20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
        >
          <ComicPanel className="text-center mb-8">
            <h1 className="text-5xl mb-4" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-blue)', textShadow: '3px 3px 0px var(--primary-yellow), 6px 6px 0px var(--border-ink)' }}>
              <SettingsIcon size={48} className="inline-block mr-3" style={{ verticalAlign: 'middle' }} />
              {t('settings.title')}
            </h1>
            <p className="text-lg font-semibold">{t('settings.description')}</p>
          </ComicPanel>
        </motion.div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Language Settings */}
          <motion.div
            initial={{ x: -20, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            transition={{ delay: 0.2 }}
          >
            <ComicPanel data-testid="language-settings-panel">
              <div className="flex items-center gap-3 mb-4">
                <Globe size={32} style={{ color: 'var(--primary-blue)' }} />
                <h2 className="text-3xl" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--ink)' }}>
                  {t('settings.language')}
                </h2>
              </div>
              
              <p className="text-base font-semibold mb-4">{t('settings.selectLanguage')}</p>
              
              <div className="mb-4">
                <label className="block text-sm font-semibold mb-2" style={{ color: 'var(--ink-2)' }}>
                  {t('settings.currentLanguage')}: <strong>{languages.find(l => l.code === i18n.language)?.name || 'English'}</strong>
                </label>
                <select
                  value={i18n.language}
                  onChange={handleLanguageChange}
                  className="w-full p-3 text-lg font-semibold"
                  style={{
                    background: 'var(--surface)',
                    border: '3px solid var(--border-ink)',
                    borderRadius: 'var(--radius-button)',
                    color: 'var(--ink)',
                    cursor: 'pointer',
                  }}
                  data-testid="language-selector"
                >
                  {languages.map((lang) => (
                    <option key={lang.code} value={lang.code}>
                      {lang.name}
                    </option>
                  ))}
                </select>
              </div>

              <SpeechBubble className="mt-6 text-sm">
                <span className="font-semibold">💡 {t('settings.selectLanguage')}</span>
              </SpeechBubble>
            </ComicPanel>
          </motion.div>

          {/* About Section */}
          <motion.div
            initial={{ x: 20, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            transition={{ delay: 0.3 }}
          >
            <ComicPanel>
              <div className="flex items-center gap-3 mb-4">
                <Zap size={32} style={{ color: 'var(--primary-red)' }} />
                <h2 className="text-3xl" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--ink)' }}>
                  {t('settings.about')}
                </h2>
              </div>
              
              <p className="text-base font-semibold mb-6">{t('settings.aboutDesc')}</p>

              <div className="mb-6">
                <h3 className="text-xl mb-3" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-blue)' }}>
                  {t('settings.superpowers')}
                </h3>
                <ul className="space-y-2">
                  <li className="flex items-start gap-2">
                    <SoundEffectBadge variant="red" rotation={-5} className="text-xs flex-shrink-0">POW</SoundEffectBadge>
                    <span className="font-semibold">{t('settings.feature1')}</span>
                  </li>
                  <li className="flex items-start gap-2">
                    <SoundEffectBadge variant="yellow" rotation={3} className="text-xs flex-shrink-0">ZAP</SoundEffectBadge>
                    <span className="font-semibold">{t('settings.feature2')}</span>
                  </li>
                  <li className="flex items-start gap-2">
                    <SoundEffectBadge variant="blue" rotation={-3} className="text-xs flex-shrink-0">BAM</SoundEffectBadge>
                    <span className="font-semibold">{t('settings.feature3')}</span>
                  </li>
                  <li className="flex items-start gap-2">
                    <SoundEffectBadge variant="green" rotation={5} className="text-xs flex-shrink-0">WOW</SoundEffectBadge>
                    <span className="font-semibold">{t('settings.feature4')}</span>
                  </li>
                  <li className="flex items-start gap-2">
                    <SoundEffectBadge variant="red" rotation={-7} className="text-xs flex-shrink-0">ZOW</SoundEffectBadge>
                    <span className="font-semibold">{t('settings.feature5')}</span>
                  </li>
                </ul>
              </div>

              <div>
                <h3 className="text-xl mb-2" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-yellow)' }}>
                  {t('settings.techStack')}
                </h3>
                <p className="text-sm font-semibold opacity-70">{t('settings.techStackDesc')}</p>
              </div>
            </ComicPanel>
          </motion.div>
        </div>
      </div>
    </div>
  );
}

export default Settings;
