/**
 * Video Utilities for LoreHunter AI
 * Handles video duration checking and frame extraction for AI analysis
 */

/**
 * Check if a video duration exceeds the maximum allowed time
 * @param {File} file - Video file object
 * @param {number} maxDurationSeconds - Maximum duration in seconds (default: 120)
 * @returns {Promise<{valid: boolean, duration: number, error?: string}>}
 */
export const checkVideoDuration = (file, maxDurationSeconds = 120) => {
  return new Promise((resolve) => {
    const video = document.createElement('video');
    video.preload = 'metadata';

    video.onloadedmetadata = () => {
      window.URL.revokeObjectURL(video.src);
      const duration = video.duration;
      
      if (duration > maxDurationSeconds) {
        resolve({
          valid: false,
          duration: Math.round(duration),
          error: `Video duration (${Math.round(duration)}s) exceeds maximum allowed (${maxDurationSeconds}s)`
        });
      } else {
        resolve({
          valid: true,
          duration: Math.round(duration)
        });
      }
    };

    video.onerror = () => {
      resolve({
        valid: false,
        duration: 0,
        error: 'Unable to load video file'
      });
    };

    video.src = URL.createObjectURL(file);
  });
};

/**
 * Extract frames from video at regular intervals
 * @param {File|Blob} videoFile - Video file or blob
 * @param {number} numFrames - Number of frames to extract (default: 5)
 * @returns {Promise<string[]>} Array of base64 image data URLs
 */
export const extractVideoFrames = (videoFile, numFrames = 5) => {
  return new Promise((resolve, reject) => {
    const video = document.createElement('video');
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    const frames = [];

    video.preload = 'metadata';
    video.muted = true;

    video.onloadedmetadata = () => {
      const duration = video.duration;
      const interval = duration / (numFrames + 1);

      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;

      let frameCount = 0;

      const captureFrame = () => {
        if (frameCount >= numFrames) {
          window.URL.revokeObjectURL(video.src);
          resolve(frames);
          return;
        }

        const targetTime = interval * (frameCount + 1);
        video.currentTime = targetTime;
      };

      video.onseeked = () => {
        context.drawImage(video, 0, 0, canvas.width, canvas.height);
        const frameData = canvas.toDataURL('image/jpeg', 0.8);
        frames.push(frameData);
        frameCount++;
        captureFrame();
      };

      video.onerror = () => {
        reject(new Error('Error processing video'));
      };

      captureFrame();
    };

    video.src = URL.createObjectURL(videoFile);
  });
};

/**
 * Extract a single frame from video at specific time
 * @param {File|Blob} videoFile - Video file or blob
 * @param {number} timeInSeconds - Time position to extract frame
 * @returns {Promise<string>} Base64 image data URL
 */
export const extractFrameAtTime = (videoFile, timeInSeconds = 0) => {
  return new Promise((resolve, reject) => {
    const video = document.createElement('video');
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');

    video.preload = 'metadata';
    video.muted = true;

    video.onloadedmetadata = () => {
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      video.currentTime = Math.min(timeInSeconds, video.duration);
    };

    video.onseeked = () => {
      context.drawImage(video, 0, 0, canvas.width, canvas.height);
      const frameData = canvas.toDataURL('image/jpeg', 0.8);
      window.URL.revokeObjectURL(video.src);
      resolve(frameData);
    };

    video.onerror = () => {
      reject(new Error('Error extracting frame from video'));
    };

    video.src = URL.createObjectURL(videoFile);
  });
};

/**
 * Format seconds to MM:SS display
 * @param {number} seconds - Duration in seconds
 * @returns {string} Formatted time string
 */
export const formatTime = (seconds) => {
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

/**
 * Check if file is a video
 * @param {File} file - File object
 * @returns {boolean}
 */
export const isVideoFile = (file) => {
  return file && file.type.startsWith('video/');
};

/**
 * Check if file is an image
 * @param {File} file - File object
 * @returns {boolean}
 */
export const isImageFile = (file) => {
  return file && file.type.startsWith('image/');
};
