import React from 'react';

/**
 * ComicPanel - A Card wrapper with thick border, offset shadow, and subtle halftone overlay
 * Represents a classic comic book panel aesthetic
 */
export const ComicPanel = ({ children, className = '', ...props }) => {
  return (
    <div
      className={`relative overflow-hidden p-6 ${className}`}
      style={{
        background: 'var(--surface)',
        border: 'var(--border-w-panel) solid var(--border-ink)',
        borderRadius: 'var(--radius-panel)',
        boxShadow: 'var(--shadow-panel)',
      }}
      {...props}
    >
      {/* Subtle halftone overlay */}
      <div
        className="absolute inset-0 pointer-events-none opacity-30"
        style={{
          backgroundImage: 'radial-gradient(circle, rgba(0,0,0,0.08) 1px, transparent 1px)',
          backgroundSize: '10px 10px',
        }}
      />
      
      {/* Content */}
      <div className="relative z-10">{children}</div>
    </div>
  );
};

export default ComicPanel;
