import React from 'react';
import { motion } from 'framer-motion';
import { ArrowLeft, Film, Tv, BookOpen, Gamepad2, Calendar, MapPin, CheckCircle, XCircle, Zap, Sparkles, TrendingUp, Link2 } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import ComicPanel from '../components/ComicPanel';
import { SpeechBubble } from '../components/SpeechBubble';
import SoundEffectBadge from '../components/SoundEffectBadge';
import PosterWithFallback from '../components/PosterWithFallback';

function ResultDetail({ scan, onBack }) {
  const { t } = useTranslation();
  
  if (!scan) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <ComicPanel>
          <p className="text-xl">{t('results.noData') || 'No scan data available'}</p>
          <button className="btn btn-primary mt-4" onClick={onBack}>
            <ArrowLeft size={20} />
            {t('results.back') || 'Back'}
          </button>
        </ComicPanel>
      </div>
    );
  }

  const theory = scan.theory || {};
  const visionData = scan.visual_analysis || {};
  const projectInfo = visionData.project_info || {};
  const relatedProjects = visionData.related_projects || [];
  const visualFacts = visionData.visual_facts || [];
  const easterEggs = visionData.easter_eggs || [];
  const predictions = visionData.predictions || theory.predictions || [];
  const deepLore = visionData.deep_lore || theory.theory_summary || '';
  const characters = visionData.characters || [];
  
  const getSourceIcon = (type) => {
    const t = type?.toLowerCase() || '';
    if (t.includes('movie') || t.includes('фільм')) return <Film size={20} />;
    if (t.includes('series') || t.includes('серіал')) return <Tv size={20} />;
    if (t.includes('comic') || t.includes('комікс')) return <BookOpen size={20} />;
    if (t.includes('game') || t.includes('гра')) return <Gamepad2 size={20} />;
    return <Film size={20} />;
  };

  const getStatusColor = (status) => {
    const s = status?.toLowerCase() || '';
    if (s.includes('ongoing') || s.includes('триває')) return 'text-green-600';
    if (s.includes('completed') || s.includes('завершено')) return 'text-blue-600';
    if (s.includes('cancelled') || s.includes('скасовано')) return 'text-red-600';
    return 'text-gray-600';
  };

  return (
    <div className="min-h-screen pb-20" style={{ background: 'var(--bg-primary)' }}>
      <div className="container mx-auto px-4 py-6 max-w-6xl">
        {/* Back Button */}
        <motion.button
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
          onClick={onBack}
          className="btn btn-secondary mb-6 flex items-center gap-2"
          data-testid="back-button"
        >
          <ArrowLeft size={20} />
          {t('results.back') || 'Назад'}
        </motion.button>

        <SoundEffectBadge variant="yellow" className="mb-6">
          ANALYSIS COMPLETE!
        </SoundEffectBadge>

        {/* ============ PROJECT INFO CARD ============ */}
        {projectInfo.title && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="mb-8"
          >
            <ComicPanel>
              <h2 className="text-2xl mb-4" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-red)' }}>
                📊 PROJECT INFO
              </h2>
              
              <div className="grid md:grid-cols-[300px_1fr] gap-6">
                {/* Poster - Left (With 4-Tier Fallback System) */}
                <div className="flex justify-center md:justify-start">
                  <PosterWithFallback
                    posterUrl={projectInfo.poster_url}
                    title={projectInfo.title}
                    year={projectInfo.release_year || projectInfo.releaseYear}
                    className="source-poster w-full max-w-[300px] h-auto rounded-lg"
                    style={{ 
                      border: '4px solid var(--primary-blue)',
                      boxShadow: '6px 6px 0px rgba(0,0,0,0.3)'
                    }}
                  />
                </div>

                {/* Fact Sheet - Right */}
                <div className="space-y-4">
                  <h1 className="text-3xl md:text-4xl font-bold" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-blue)' }}>
                    {projectInfo.title}
                  </h1>

                  <div className="grid sm:grid-cols-2 gap-4">
                    {/* Release Year */}
                    <div className="metadata-item">
                      <div className="flex items-center gap-2 mb-1">
                        <Calendar size={18} style={{ color: 'var(--primary-red)' }} />
                        <span className="font-bold text-sm uppercase">{t('results.releaseYear') || 'Release Year'}</span>
                      </div>
                      <p className="text-2xl font-bold">{projectInfo.release_year || projectInfo.releaseYear || 'N/A'}</p>
                    </div>

                    {/* Source Type / Medium */}
                    <div className="metadata-item">
                      <div className="flex items-center gap-2 mb-1">
                        {getSourceIcon(projectInfo.source_type || projectInfo.medium)}
                        <span className="font-bold text-sm uppercase">{t('results.medium') || 'Type'}</span>
                      </div>
                      <p className="text-xl font-semibold">{projectInfo.medium || projectInfo.source_type || 'N/A'}</p>
                    </div>

                    {/* Status */}
                    <div className="metadata-item">
                      <div className="flex items-center gap-2 mb-1">
                        {projectInfo.status?.toLowerCase().includes('completed') || projectInfo.status?.toLowerCase().includes('завершено') ? 
                          <CheckCircle size={18} className="text-green-600" /> : 
                          <XCircle size={18} className="text-red-600" />
                        }
                        <span className="font-bold text-sm uppercase">{t('results.status') || 'Status'}</span>
                      </div>
                      <p className={`text-xl font-semibold ${getStatusColor(projectInfo.status)}`}>
                        {projectInfo.status || projectInfo.productionStatus || 'N/A'}
                      </p>
                    </div>

                    {/* Country */}
                    <div className="metadata-item">
                      <div className="flex items-center gap-2 mb-1">
                        <MapPin size={18} style={{ color: 'var(--primary-blue)' }} />
                        <span className="font-bold text-sm uppercase">{t('results.country') || 'Country'}</span>
                      </div>
                      <p className="text-xl font-semibold">{projectInfo.country || 'N/A'}</p>
                    </div>
                  </div>

                  {/* Exact Episode (if TV series) */}
                  {(projectInfo.season || projectInfo.episode_number) && (
                    <div className="metadata-item">
                      <span className="font-bold text-sm uppercase">Episode</span>
                      <p className="text-xl font-semibold">
                        {projectInfo.season && `Season ${projectInfo.season}`}
                        {projectInfo.episode_number && `, Episode ${projectInfo.episode_number}`}
                      </p>
                    </div>
                  )}

                  {/* Universe */}
                  {projectInfo.universe && (
                    <div className="metadata-item">
                      <span className="font-bold text-sm uppercase">Universe</span>
                      <p className="text-xl font-semibold">{projectInfo.universe}</p>
                    </div>
                  )}
                </div>
              </div>
            </ComicPanel>
          </motion.div>
        )}

        {/* ============ RELATED PROJECTS ============ */}
        {relatedProjects.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
            className="mb-8"
          >
            <ComicPanel>
              <h3 className="text-2xl mb-4 flex items-center gap-2" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-red)' }}>
                <Link2 size={24} />
                RELATED PROJECTS
              </h3>
              <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {relatedProjects.map((project, index) => (
                  <div key={index} className="metadata-item">
                    <p className="font-bold text-lg">{project.title || 'Unknown Title'}</p>
                    <p className="text-sm text-gray-600">
                      {project.type || 'Unknown'} • {project.year || 'N/A'}
                    </p>
                    <p className="text-xs font-semibold mt-1" style={{ color: 'var(--primary-blue)' }}>
                      {project.relation || 'Related'}
                    </p>
                  </div>
                ))}
              </div>
            </ComicPanel>
          </motion.div>
        )}

        {/* ============ CHARACTERS ============ */}
        {characters.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="mb-8"
          >
            <ComicPanel>
              <h3 className="text-2xl mb-4" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-blue)' }}>
                👤 CHARACTERS
              </h3>
              <div className="space-y-3">
                {characters.map((char, index) => (
                  <div key={index} className="flex items-start gap-3 p-3 bg-gray-50 rounded-lg border-2 border-gray-300">
                    <Sparkles size={20} style={{ color: 'var(--primary-yellow)' }} className="flex-shrink-0 mt-1" />
                    <div>
                      <p className="font-bold text-lg">{char.name}</p>
                      {char.actor && <p className="text-sm text-gray-600">Актор: {char.actor}</p>}
                      {char.costume && <p className="text-sm">{char.costume}</p>}
                    </div>
                  </div>
                ))}
              </div>
            </ComicPanel>
          </motion.div>
        )}

        {/* ============ VISUAL FACTS (Bullet Points) ============ */}
        {visualFacts.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="mb-8"
          >
            <ComicPanel>
              <h3 className="text-2xl mb-4 flex items-center gap-2" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-red)' }}>
                <Zap size={24} />
                VISUAL FACTS
              </h3>
              <ul className="space-y-2">
                {visualFacts.map((fact, index) => (
                  <li key={index} className="flex items-start gap-3">
                    <span className="text-2xl flex-shrink-0">•</span>
                    <span className="font-semibold text-lg">{fact}</span>
                  </li>
                ))}
              </ul>
            </ComicPanel>
          </motion.div>
        )}

        {/* ============ EASTER EGGS with Thumbnails ============ */}
        {easterEggs.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
            className="mb-8"
          >
            <ComicPanel>
              <h3 className="text-2xl mb-4 flex items-center gap-2" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-yellow)' }}>
                🥚 EASTER EGGS
              </h3>
              <div className="space-y-4">
                {easterEggs.map((egg, index) => {
                  // Extract comic issue or reference for thumbnail
                  const reference = egg.reference || '';
                  const getThumbnailUrl = (ref) => {
                    // For Marvel/DC comics, try to generate a cover image URL
                    if (ref.includes('Marvel') || ref.includes('Amazing Spider-Man') || ref.includes('Iron Fist')) {
                      // Use a placeholder with the reference text
                      return `https://via.placeholder.com/80x120/dc2626/ffffff?text=${encodeURIComponent(ref.split('(')[0].trim())}`;
                    }
                    return null;
                  };
                  
                  const thumbnailUrl = getThumbnailUrl(reference);
                  
                  return (
                    <div key={index} className="border-l-4 border-yellow-500 pl-4 py-3 bg-yellow-50 flex gap-4">
                      {thumbnailUrl && (
                        <img 
                          src={thumbnailUrl} 
                          alt={reference}
                          className="evidence-thumbnail flex-shrink-0"
                          style={{ 
                            width: '80px', 
                            height: '120px',
                            objectFit: 'cover',
                            borderRadius: '4px',
                            border: '2px solid var(--primary-yellow)'
                          }}
                        />
                      )}
                      <div className="flex-1">
                        <p className="font-bold text-lg">{egg.fact}</p>
                        <p className="text-sm text-gray-700 mt-1 flex items-center gap-2">
                          <BookOpen size={16} className="flex-shrink-0" />
                          <span className="font-semibold">Reference:</span> {reference}
                        </p>
                        {egg.significance && (
                          <p className="text-sm text-gray-600 mt-1 italic">
                            ⚡ {egg.significance}
                          </p>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </ComicPanel>
          </motion.div>
        )}

        {/* ============ ПРОГНОЗИ (Short - Max 2 sentences) ============ */}
        {predictions.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.5 }}
            className="mb-8"
          >
            <ComicPanel>
              <h3 className="text-2xl mb-4 flex items-center gap-2" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-blue)' }}>
                <TrendingUp size={24} />
                PREDICTIONS
              </h3>
              <div className="space-y-3">
                {predictions.map((prediction, index) => (
                  <div key={index} className="flex items-start gap-3">
                    <span className="text-2xl font-bold flex-shrink-0" style={{ color: 'var(--primary-red)' }}>
                      {index + 1}.
                    </span>
                    <p className="text-lg font-semibold">{prediction}</p>
                  </div>
                ))}
              </div>
            </ComicPanel>
          </motion.div>
        )}

        {/* ============ DEEP LORE (Comic Bubble) ============ */}
        {deepLore && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.6 }}
            className="mb-8"
          >
            <h3 className="text-2xl mb-4 flex items-center gap-2" style={{ fontFamily: 'Bangers, system-ui', color: 'var(--primary-red)' }}>
              📖 DEEP LORE
            </h3>
            <div className="theory-bubble">
              <p className="text-lg leading-relaxed">{deepLore}</p>
            </div>
          </motion.div>
        )}

        {/* Scanned Image */}
        {scan.image_url && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.7 }}
            className="mb-8"
          >
            <ComicPanel>
              <h3 className="text-xl mb-3" style={{ fontFamily: 'Bangers, system-ui' }}>
                Scanned Image
              </h3>
              <img
                src={scan.image_url}
                alt="Scanned content"
                className="w-full max-w-2xl mx-auto border-4 border-[var(--primary-blue)] rounded-lg"
              />
            </ComicPanel>
          </motion.div>
        )}
      </div>
    </div>
  );
}

export default ResultDetail;
