import React from 'react';

/**
 * SpeechBubble - Yellow speech bubble with tail pointer
 * Used for tips, messages, and fun callouts
 */
export const SpeechBubble = ({ children, className = '', tailPosition = 'bottom-left', ...props }) => {
  const tailConfig = {
    'bottom-left': {
      tail: { bottom: '-20px', left: '40px' },
      tailInner: { bottom: '-14px', left: '44px' },
    },
    'bottom-right': {
      tail: { bottom: '-20px', right: '40px' },
      tailInner: { bottom: '-14px', right: '44px' },
    },
    'top-left': {
      tail: { top: '-20px', left: '40px' },
      tailInner: { top: '-14px', left: '44px' },
    },
  };

  const config = tailConfig[tailPosition] || tailConfig['bottom-left'];

  return (
    <div
      className={`relative p-6 font-semibold ${className}`}
      style={{
        background: 'var(--primary-yellow)',
        color: 'var(--ink)',
        border: 'var(--border-w-input) solid var(--border-ink)',
        borderRadius: 'var(--radius-panel)',
        boxShadow: 'var(--shadow-button)',
      }}
      {...props}
    >
      {children}
      
      {/* Tail outer (border) */}
      <div 
        className="absolute w-0 h-0"
        style={{
          ...config.tail,
          borderLeft: '15px solid transparent',
          borderRight: '15px solid transparent',
          borderTop: tailPosition.startsWith('top') ? 'none' : '20px solid var(--border-ink)',
          borderBottom: tailPosition.startsWith('top') ? '20px solid var(--border-ink)' : 'none',
        }}
      />
      
      {/* Tail inner (fill) */}
      <div 
        className="absolute w-0 h-0 z-[1]"
        style={{
          ...config.tailInner,
          borderLeft: '11px solid transparent',
          borderRight: '11px solid transparent',
          borderTop: tailPosition.startsWith('top') ? 'none' : '16px solid var(--primary-yellow)',
          borderBottom: tailPosition.startsWith('top') ? '16px solid var(--primary-yellow)' : 'none',
        }}
      />
    </div>
  );
};

/**
 * ThoughtBubble - Cloud-style thought bubble (circular styling)
 * Used for character thoughts and internal dialogue
 */
export const ThoughtBubble = ({ children, className = '', ...props }) => {
  return (
    <div className="relative inline-block">
      {/* Main thought bubble */}
      <div
        className={`relative p-6 font-semibold ${className}`}
        style={{
          background: 'var(--surface)',
          color: 'var(--ink)',
          border: 'var(--border-w-input) solid var(--border-ink)',
          borderRadius: 'var(--radius-panel)',
          boxShadow: 'var(--shadow-button)',
        }}
        {...props}
      >
        {children}
      </div>
      
      {/* Thought bubble dots */}
      <div className="absolute -bottom-8 left-8 flex gap-2">
        <div 
          className="rounded-full"
          style={{
            width: '12px',
            height: '12px',
            background: 'var(--surface)',
            border: '2px solid var(--border-ink)',
          }}
        />
        <div 
          className="rounded-full"
          style={{
            width: '8px',
            height: '8px',
            background: 'var(--surface)',
            border: '2px solid var(--border-ink)',
          }}
        />
      </div>
    </div>
  );
};

export default SpeechBubble;
